   306→// Root MemRegions are memory areas that contain objects which references are
   307→// roots wrt to the marking. They must be scanned before marking to maintain the
   308→// SATB invariant.
   309→// Typically they contain the areas from TAMS to top of the regions.
   310→// We could scan and mark through these objects during the concurrent start pause,
   311→// but for pause time reasons we move this work to the concurrent phase.
   312→// We need to complete this procedure before we can evacuate a particular region
   313→// because evacuation might determine that some of these "root objects" are dead,
   314→// potentially dropping some required references.
   315→// Root MemRegions comprise of the contents of survivor regions at the end
   316→// of the GC, and any objects copied into the old gen during GC.
   317→class G1CMRootMemRegions {
   318→  // The set of root MemRegions.
   319→  MemRegion* _root_regions;
   320→  size_t const _max_regions;
   321→
   322→  volatile size_t _num_root_regions; // Actual number of root regions.
   323→
   324→  volatile size_t _claimed_root_regions; // Number of root regions currently claimed.
   325→
   326→  volatile bool _scan_in_progress;
   327→  volatile bool _should_abort;
   328→
   329→  void notify_scan_done();
   330→
   331→public:
   332→  G1CMRootMemRegions(uint const max_regions);
   333→  ~G1CMRootMemRegions();
   334→
   335→  // Reset the data structure to allow addition of new root regions.
   336→  void reset();
   337→
   338→  void add(HeapWord* start, HeapWord* end);
   339→
   340→  // Reset the claiming / scanning of the root regions.
   341→  void prepare_for_scan();
   342→
   343→  // Forces get_next() to return null so that the iteration aborts early.
   344→  void abort() { _should_abort = true; }
   345→
   346→  // Return true if the CM thread are actively scanning root regions,
   347→  // false otherwise.
   348→  bool scan_in_progress() { return _scan_in_progress; }
   349→
   350→  // Claim the next root MemRegion to scan atomically, or return null if
   351→  // all have been claimed.
   352→  const MemRegion* claim_next();
   353→
   354→  // The number of root regions to scan.
   355→  uint num_root_regions() const;
   356→
   357→  // Is the given memregion contained in the root regions; the MemRegion must
   358→  // match exactly.
   359→  bool contains(const MemRegion mr) const;
   360→
   361→  void cancel_scan();
   362→
   363→  // Flag that we're done with root region scanning and notify anyone
   364→  // who's waiting on it. If aborted is false, assume that all regions
   365→  // have been claimed.
   366→  void scan_finished();
   367→
   368→  // If CM threads are still scanning root regions, wait until they
   369→  // are done. Return true if we had to wait, false otherwise.
   370→  bool wait_until_scan_finished();
   371→};
