   373→// This class manages data structures and methods for doing liveness analysis in
   374→// G1's concurrent cycle.
   375→class G1ConcurrentMark : public CHeapObj<mtGC> {
   376→  friend class G1CMBitMapClosure;
   377→  friend class G1CMConcurrentMarkingTask;
   378→  friend class G1CMDrainMarkingStackClosure;
   379→  friend class G1CMKeepAliveAndDrainClosure;
   380→  friend class G1CMRefProcProxyTask;
   381→  friend class G1CMRemarkTask;
   382→  friend class G1CMRootRegionScanTask;
   383→  friend class G1CMTask;
   384→  friend class G1ConcurrentMarkThread;
   385→
   386→  G1ConcurrentMarkThread* _cm_thread;     // The thread doing the work
   387→  G1CollectedHeap*        _g1h;           // The heap
   388→
   389→  // Concurrent marking support structures
   390→  G1CMBitMap              _mark_bitmap;
   391→
   392→  // Heap bounds
   393→  MemRegion const         _heap;
   394→
   395→  // Root region tracking and claiming
   396→  G1CMRootMemRegions      _root_regions;
   397→
   398→  // For grey objects
   399→  G1CMMarkStack           _global_mark_stack; // Grey objects behind global finger
   400→  HeapWord* volatile      _finger;            // The global finger, region aligned,
   401→                                              // always pointing to the end of the
   402→                                              // last claimed region
   403→
   404→  uint                    _worker_id_offset;
   405→  uint                    _max_num_tasks;    // Maximum number of marking tasks
   406→  uint                    _num_active_tasks; // Number of tasks currently active
   407→  G1CMTask**              _tasks;            // Task queue array (max_worker_id length)
   408→
   409→  G1CMTaskQueueSet*       _task_queues; // Task queue set
   410→  TaskTerminator          _terminator;  // For termination
   411→
   412→  // Two sync barriers that are used to synchronize tasks when an
   413→  // overflow occurs. The algorithm is the following. All tasks enter
   414→  // the first one to ensure that they have all stopped manipulating
   415→  // the global data structures. After they exit it, they re-initialize
   416→  // their data structures and task 0 re-initializes the global data
   417→  // structures. Then, they enter the second sync barrier. This
   418→  // ensure, that no task starts doing work before all data
   419→  // structures (local and global) have been re-initialized. When they
   420→  // exit it, they are free to start working again.
   421→  WorkerThreadsBarrierSync     _first_overflow_barrier_sync;
   422→  WorkerThreadsBarrierSync     _second_overflow_barrier_sync;
   423→
   424→  // Number of completed mark cycles.
   425→  volatile uint           _completed_mark_cycles;
   426→
   427→  // This is set by any task, when an overflow on the global data
   428→  // structures is detected
   429→  volatile bool           _has_overflown;
   430→  // True: marking is concurrent, false: we're in remark
   431→  volatile bool           _concurrent;
   432→  // Set at the end of a Full GC so that marking aborts
   433→  volatile bool           _has_aborted;
   434→
   435→  // Used when remark aborts due to an overflow to indicate that
   436→  // another concurrent marking phase should start
   437→  volatile bool           _restart_for_overflow;
   438→
   439→  ConcurrentGCTimer*      _gc_timer_cm;
   440→
   441→  G1OldTracer*            _gc_tracer_cm;
   442→
   443→  // Timing statistics. All of them are in ms
   444→  NumberSeq _remark_times;
   445→  NumberSeq _remark_mark_times;
   446→  NumberSeq _remark_weak_ref_times;
   447→  NumberSeq _cleanup_times;
   448→
   449→  double*   _accum_task_vtime;   // Accumulated task vtime
   450→
   451→  WorkerThreads* _concurrent_workers;
   452→  uint      _num_concurrent_workers; // The number of marking worker threads we're using
   453→  uint      _max_concurrent_workers; // Maximum number of marking worker threads
   454→
   455→  enum class VerifyLocation {
   456→    RemarkBefore,
   457→    RemarkAfter,
   458→    RemarkOverflow,
   459→    CleanupBefore,
   460→    CleanupAfter
   461→  };
   462→  static const char* verify_location_string(VerifyLocation location);
   463→  void verify_during_pause(G1HeapVerifier::G1VerifyType type,
   464→                           VerifyLocation location);
   465→
   466→  void finalize_marking();
   467→
   468→  void weak_refs_work();
   469→
   470→  // After reclaiming empty regions, update heap sizes.
   471→  void compute_new_sizes();
   472→
   473→  // Resets all the marking data structures. Called when we have to restart
   474→  // marking or when marking completes (via set_non_marking_state below).
   475→  void reset_marking_for_restart();
   476→
   477→  // We do this after we're done with marking so that the marking data
   478→  // structures are initialized to a sensible and predictable state.
   479→  void reset_at_marking_complete();
   480→
   481→  // Called to indicate how many threads are currently active.
   482→  void set_concurrency(uint active_tasks);
   483→
   484→  // Should be called to indicate which phase we're in (concurrent
   485→  // mark or remark) and how many threads are currently active.
   486→  void set_concurrency_and_phase(uint active_tasks, bool concurrent);
   487→
   488→  // Prints all gathered CM-related statistics
   489→  void print_stats();
   490→
   491→  HeapWord*           finger()       { return _finger;   }
   492→  bool                concurrent()   { return _concurrent; }
   493→  uint                active_tasks() { return _num_active_tasks; }
   494→  TaskTerminator*     terminator()   { return &_terminator; }
   495→
   496→  // Claims the next available region to be scanned by a marking
   497→  // task/thread. It might return null if the next region is empty or
   498→  // we have run out of regions. In the latter case, out_of_regions()
   499→  // determines whether we've really run out of regions or the task
   500→  // should call claim_region() again. This might seem a bit
   501→  // awkward. Originally, the code was written so that claim_region()
   502→  // either successfully returned with a non-empty region or there
   503→  // were no more regions to be claimed. The problem with this was
   504→  // that, in certain circumstances, it iterated over large chunks of
   505→  // the heap finding only empty regions and, while it was working, it
   506→  // was preventing the calling task to call its regular clock
   507→  // method. So, this way, each task will spend very little time in
   508→  // claim_region() and is allowed to call the regular clock method
   509→  // frequently.
   510→  G1HeapRegion* claim_region(uint worker_id);
   511→
   512→  // Determines whether we've run out of regions to scan. Note that
   513→  // the finger can point past the heap end in case the heap was expanded
   514→  // to satisfy an allocation without doing a GC. This is fine, because all
   515→  // objects in those regions will be considered live anyway because of
   516→  // SATB guarantees (i.e. their TAMS will be equal to bottom).
   517→  bool out_of_regions() { return _finger >= _heap.end(); }
   518→
   519→  // Returns the task with the given id
   520→  G1CMTask* task(uint id) {
   521→    // During concurrent start we use the parallel gc threads to do some work, so
   522→    // we can only compare against _max_num_tasks.
   523→    assert(id < _max_num_tasks, "Task id %u not within bounds up to %u", id, _max_num_tasks);
   524→    return _tasks[id];
   525→  }
   526→
   527→  // Access / manipulation of the overflow flag which is set to
   528→  // indicate that the global stack has overflown
   529→  bool has_overflown()           { return _has_overflown; }
   530→  void set_has_overflown()       { _has_overflown = true; }
   531→  void clear_has_overflown()     { _has_overflown = false; }
   532→  bool restart_for_overflow()    { return _restart_for_overflow; }
   533→
   534→  // Methods to enter the two overflow sync barriers
   535→  void enter_first_sync_barrier(uint worker_id);
