   278→  // chunk may contain up to EntriesPerChunk elements. If there are less, the last
   279→  // element in the array is a null pointer.
   280→  bool par_pop_chunk(G1TaskQueueEntry* buffer);
   281→
   282→  // Return whether the chunk list is empty. Racy due to unsynchronized access to
   283→  // _chunk_list.
   284→  bool is_empty() const { return _chunk_list == nullptr; }
   285→
   286→  size_t capacity() const  { return _chunk_allocator.capacity(); }
   287→
   288→  void set_should_grow() {
   289→    _chunk_allocator.set_should_grow();
   290→  }
   291→
   292→  // Expand the stack, typically in response to an overflow condition
   293→  void expand();
   294→
   295→  // Return the approximate number of oops on this mark stack. Racy due to
   296→  // unsynchronized access to _chunks_in_chunk_list.
   297→  size_t size() const { return _chunks_in_chunk_list * EntriesPerChunk; }
   298→
   299→  void set_empty();
   300→
   301→  // Apply Fn to every oop on the mark stack. The mark stack must not
   302→  // be modified while iterating.
   303→  template<typename Fn> void iterate(Fn fn) const PRODUCT_RETURN;
   304→};
