   759→
   760→  // Region this task is scanning, null if we're not scanning any
   761→  G1HeapRegion*               _curr_region;
   762→  // Local finger of this task, null if we're not scanning a region
   763→  HeapWord*                   _finger;
   764→  // Limit of the region this task is scanning, null if we're not scanning one
   765→  HeapWord*                   _region_limit;
   766→
   767→  // Number of words this task has scanned
   768→  size_t                      _words_scanned;
   769→  // When _words_scanned reaches this limit, the regular clock is
   770→  // called. Notice that this might be decreased under certain
   771→  // circumstances (i.e. when we believe that we did an expensive
   772→  // operation).
   773→  size_t                      _words_scanned_limit;
