   110→G1CMMarkStack::G1CMMarkStack() :
   111→  _chunk_allocator() {
   112→  set_empty();
   113→}
   114→
   115→size_t G1CMMarkStack::capacity_alignment() {
   116→  return (size_t)lcm(os::vm_allocation_granularity(), sizeof(TaskQueueEntryChunk)) / sizeof(G1TaskQueueEntry);
   117→}
   118→
   119→bool G1CMMarkStack::initialize() {
   120→  guarantee(_chunk_allocator.capacity() == 0, "G1CMMarkStack already initialized.");
   121→
   122→  size_t initial_capacity = MarkStackSize;
   123→  size_t max_capacity = MarkStackSizeMax;
   124→
   125→  size_t const TaskEntryChunkSizeInVoidStar = sizeof(TaskQueueEntryChunk) / sizeof(G1TaskQueueEntry);
   126→
   127→  size_t max_num_chunks = align_up(max_capacity, capacity_alignment()) / TaskEntryChunkSizeInVoidStar;
   128→  size_t initial_num_chunks = align_up(initial_capacity, capacity_alignment()) / TaskEntryChunkSizeInVoidStar;
   129→
   130→  initial_num_chunks = round_up_power_of_2(initial_num_chunks);
   131→  max_num_chunks = MAX2(initial_num_chunks, max_num_chunks);
   132→
   133→  size_t limit = (INT_MAX - 1);
   134→  max_capacity = MIN2((max_num_chunks * TaskEntryChunkSizeInVoidStar), limit);
   135→  initial_capacity = MIN2((initial_num_chunks * TaskEntryChunkSizeInVoidStar), limit);
   136→
   137→  FLAG_SET_ERGO(MarkStackSizeMax, max_capacity);
   138→  FLAG_SET_ERGO(MarkStackSize, initial_capacity);
   139→
   140→  log_trace(gc)("MarkStackSize: %uk  MarkStackSizeMax: %uk", (uint)(MarkStackSize / K), (uint)(MarkStackSizeMax / K));
   141→
   142→  log_debug(gc)("Initialize mark stack with %zu chunks, maximum %zu",
   143→                initial_num_chunks, max_capacity);
   144→
   145→  return _chunk_allocator.initialize(initial_num_chunks, max_num_chunks);
   146→}
   147→
   148→G1CMMarkStack::TaskQueueEntryChunk* G1CMMarkStack::ChunkAllocator::allocate_new_chunk() {
   149→  if (_size >= _max_capacity) {
   150→    return nullptr;
   151→  }
   152→
   153→  size_t cur_idx = Atomic::fetch_then_add(&_size, 1u);
   154→
   155→  if (cur_idx >= _max_capacity) {
   156→    return nullptr;
   157→  }
   158→
   159→  size_t bucket = get_bucket(cur_idx);
   160→  if (Atomic::load_acquire(&_buckets[bucket]) == nullptr) {
   161→    if (!_should_grow) {
   162→      // Prefer to restart the CM.
   163→      return nullptr;
   164→    }
   165→
   166→    MutexLocker x(MarkStackChunkList_lock, Mutex::_no_safepoint_check_flag);
   167→    if (Atomic::load_acquire(&_buckets[bucket]) == nullptr) {
   168→      size_t desired_capacity = bucket_size(bucket) * 2;
   169→      if (!try_expand_to(desired_capacity)) {
   170→        return nullptr;
   171→      }
   172→    }
   173→  }
   174→
   175→  size_t bucket_idx = get_bucket_index(cur_idx);
   176→  TaskQueueEntryChunk* result = ::new (&_buckets[bucket][bucket_idx]) TaskQueueEntryChunk;
   177→  result->next = nullptr;
   178→  return result;
   179→}
