   145→    bool do_heap_region(G1HeapRegion* r) {
   146→      // Candidates from marking are always old; also keep regions that are already
   147→      // collection set candidates (some retained regions) in that list.
   148→      if (!r->is_old() || r->is_collection_set_candidate()) {
   149→        // Keep remembered sets and everything for these regions.
   150→        return false;
   151→      }
   152→
   153→      // Can not add a region without a remembered set to the candidates.
   154→      if (!r->rem_set()->is_tracked()) {
   155→        return false;
   156→      }
   157→
   158→      // Skip any region that is currently used as an old GC alloc region. We should
   159→      // not consider those for collection before we fill them up as the effective
   160→      // gain from them is small. I.e. we only actually reclaim from the filled part,
   161→      // as the remainder is still eligible for allocation. These objects are also
   162→      // likely to have already survived a few collections, so they might be longer
   163→      // lived anyway.
   164→      // Otherwise the Old region must satisfy the liveness condition.
   165→      bool should_add = !G1CollectedHeap::heap()->is_old_gc_alloc_region(r) &&
   166→                        G1CollectionSetChooser::region_occupancy_low_enough_for_evac(r->live_bytes());
   167→      if (should_add) {
   168→        add_region(r);
   169→      } else {
   170→        r->rem_set()->clear(true /* only_cardset */);
   171→      }
   172→      return false;
   173→    }
   174→
   175→    uint regions_added() const { return _regions_added; }
   176→  };
   177→
   178→  G1CollectedHeap* _g1h;
   179→  G1HeapRegionClaimer _hrclaimer;
   180→
   181→  uint volatile _num_regions_added;
   182→
   183→  G1BuildCandidateArray _result;
   184→
   185→  void update_totals(uint num_regions) {
   186→    if (num_regions > 0) {
   187→      Atomic::add(&_num_regions_added, num_regions);
   188→    }
   189→  }
   190→
   191→  // Early prune (remove) regions meeting the G1HeapWastePercent criteria. That
   192→  // is, either until only the minimum amount of old collection set regions are
   193→  // available (for forward progress in evacuation) or the waste accumulated by the
   194→  // removed regions is above the maximum allowed waste.
   195→  // Updates number of candidates and reclaimable bytes given.
   196→  void prune(CandidateInfo* data) {
   197→    G1Policy* p = G1CollectedHeap::heap()->policy();
   198→
   199→    uint num_candidates = Atomic::load(&_num_regions_added);
   200→
   201→    uint min_old_cset_length = p->calc_min_old_cset_length(num_candidates);
   202→    uint num_pruned = 0;
   203→    size_t wasted_bytes = 0;
   204→
   205→    if (min_old_cset_length >= num_candidates) {
   206→      // We take all of the candidate regions to provide some forward progress.
   207→      return;
   208→    }
   209→
   210→    size_t allowed_waste = p->allowed_waste_in_collection_set();
   211→    uint max_to_prune = num_candidates - min_old_cset_length;
   212→
   213→    while (true) {
   214→      G1HeapRegion* r = data[num_candidates - num_pruned - 1]._r;
   215→      size_t const reclaimable = r->reclaimable_bytes();
   216→      if (num_pruned >= max_to_prune ||
   217→          wasted_bytes + reclaimable > allowed_waste) {
   218→        break;
   219→      }
   220→      r->rem_set()->clear(true /* cardset_only */);
   221→
   222→      wasted_bytes += reclaimable;
   223→      num_pruned++;
   224→    }
